        import sailpoint.transformer.IdentityTransformer;
        Map identityModel = new HashMap();
        if(null != identityModel){
          identityModel.put("launcher",launcher);     
        }    
        IdentityTransformer transformer = new IdentityTransformer(context);
        identityModel.put(IdentityTransformer.ATTR_TRANSFORMER_CLASS, transformer.getClass().getName());
        identityModel.put(IdentityTransformer.ATTR_TRANSFORMER_OPTIONS, "");
        return identityModel;

        import sailpoint.object.Filter;
        import sailpoint.tools.Util;
        import sailpoint.object.Link;
        import sailpoint.object.QueryOptions;


        Filter appFilter = Filter.eq("links.application.name", "MDStaff - Ascension");
        Filter inactiveFilter = Filter.eq("inactive", true);        

        QueryOptions qo = new QueryOptions();
        qo.add(appFilter, inactiveFilter);

        List properties = new ArrayList();
        properties.add("name");
        Iterator iter = context.search(Identity.class, qo, properties);
				Identity identity = null;
        Object[] currentUser;
        
        while(iter.hasNext()) {
          currentUser = iter.next();

          if(currentUser != null && currentUser.length > 0 && null != currentUser[0]) {
        
            identity = context.getObjectByName(Identity.class, currentUser[0]);
        
            if(null != identity && Util.nullSafeCaseInsensitiveEq(identity.getAttribute("manualTerm") , "yes")){
              matchingUsers.add(currentUser[0]);        		
            }       
        
          }
        }

        if(null != iter){
        Util.flushIterator(iter);
        }

        return matchingUsers;

        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
		import sailpoint.api.Provisioner;

        ProvisioningPlan plan = new ProvisioningPlan();
        Identity identityObject = null; 

        wfcontext.getWorkflowCase().getTaskResult().setName("Ascension-Workflow-UpdateManualTerm");
        if(null != identityModel){
        	identityName = identityModel.get("userName");
        }

        if(null !=identityName){ 
          identityObject = context.getObjectByName(Identity.class, identityName);

          if(null != identityObject){       		
            AccountRequest iiqAcctReq = new AccountRequest();
            iiqAcctReq.setApplication("IIQ");
            iiqAcctReq.setNativeIdentity(identityName);
            iiqAcctReq.setOperation(AccountRequest.Operation.Modify);                     	       				    
            iiqAcctReq.add(new AttributeRequest("manualTerm", ProvisioningPlan.Operation.Set, "No")); 
            plan.add(iiqAcctReq);
            plan.setIdentity(identityObject);
            //comment decache //context.decache(identityObject);
            if(null != plan && !plan.isEmpty()){
              Provisioner provisioner= new Provisioner(context);
              provisioner.setNoLocking(true);
              provisioner.setOptimisticProvisioning(true);
              provisioner.execute(plan);
             	   
            }
          }
        }
